#include <stdio.h>
#include <iostream>
#include <fstream>
#include <stdlib.h>
#include <sys/time.h>
#include <string.h>
#include <assert.h>
#include <math.h>
#include <sys/resource.h>
#include <limits.h>
#include <omp.h>

#ifdef ENABLE_PARSEC_HOOKS
#include <hooks.h>
#endif

using namespace std;

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

class PStream {
public:
  virtual size_t read(float* dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_) { n = n_; }
  size_t read(float* dest, int dim, int num) override {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() override { return 0; }
  int feof() override { return n <= 0; }
  ~SimStream() override {}
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float* dest, int dim, int num) override {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() override { return std::ferror(fp); }
  int feof() override { return std::feof(fp); }
  ~FileStream() override {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define PROFILE

static bool *switch_membership;
static bool *is_center;
static int  *center_table;
static int nproc;
bool isCoordChanged;

double serial_t;
double cpu_to_gpu_t;
double gpu_to_cpu_t;
double alloc_t;
double kernel_t;
double free_t;

#ifdef PROFILE
double time_local_search = 0.0;
double time_speedy = 0.0;
double time_select_feasible = 0.0;
double time_gain = 0.0;
double time_shuffle = 0.0;
double time_gain_dist = 0.0;
double time_gain_init = 0.0;
#endif

static float *work_mem_h = nullptr;
static float *coord_h = nullptr;
static int iter = 0;

double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

int isIdentical(float *i, float *j, int D) {
  int a = 0;
  int equal = 1;
  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  return equal ? 1 : 0;
}

void allocHostMem(int num, int dim) {
  if (coord_h) free(coord_h);
  coord_h = (float*)malloc((size_t)num * (size_t)dim * sizeof(float));
}

void allocDevMem(int, int) {}
void freeDevMem() {}
void freeHostMem() {
  if (coord_h) {
    free(coord_h);
    coord_h = nullptr;
  }
}

void shuffle(Points *points) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  for (long i = 0; i < points->num - 1; i++) {
    long j = (lrand48() % (points->num - i)) + i;
    Point temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

void intshuffle(int *intarray, int length) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  for (long i = 0; i < length; i++) {
    long j = (lrand48() % (length - i)) + i;
    int temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

float dist(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float d = p1.coord[i] - p2.coord[i];
    result += d * d;
  }
  return result;
}

static inline float d_dist_host(int p1, int p2, int num, int dim, const float *coord) {
  float retval = 0.0f;
  for (int i = 0; i < dim; i++) {
    float tmp = coord[(i * num) + p1] - coord[(i * num) + p2];
    retval += tmp * tmp;
  }
  return retval;
}

float pgain(long x, Points *points, float z, long int *numcenters, int, bool *is_center_l,
            int *center_table_l, bool *switch_membership_l, bool isCoordChanged_l,
            double *serial_t_l, double *cpu_to_gpu_t_l, double *gpu_to_cpu_t_l,
            double *alloc_t_l, double *kernel_t_l, double *free_t_l) {
  double t0, t1;

  t0 = omp_get_wtime();
  int stride = (int)(*numcenters + 1);
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;
  int nThread = num;

  work_mem_h = (float*)malloc((size_t)stride * (size_t)(nThread + 1) * sizeof(float));
  if (iter == 0) allocHostMem(num, dim);

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center_l[i]) center_table_l[i] = count++;
  }

  if (isCoordChanged_l || iter == 0) {
    for (int i = 0; i < dim; i++) {
      for (int j = 0; j < num; j++) {
        coord_h[(num * i) + j] = points->p[j].coord[i];
      }
    }
  }
  t1 = omp_get_wtime();
  *serial_t_l += (t1 - t0) * 1000.0;

  t0 = omp_get_wtime();
  if (iter == 0) allocDevMem(num, dim);
  t1 = omp_get_wtime();
  *alloc_t_l += (t1 - t0) * 1000.0;

  t0 = omp_get_wtime();
  memset(switch_membership_l, 0, (size_t)num * sizeof(bool));
  memset(work_mem_h, 0, (size_t)stride * (size_t)(nThread + 1) * sizeof(float));
  t1 = omp_get_wtime();
  *cpu_to_gpu_t_l += (t1 - t0) * 1000.0;

  t0 = omp_get_wtime();
#pragma omp parallel for schedule(static)
  for (int tid = 0; tid < num; tid++) {
    float *lower = &work_mem_h[(size_t)tid * (size_t)stride];
    float x_cost = d_dist_host(tid, (int)x, num, dim, coord_h) * points->p[tid].weight;
    if (x_cost < points->p[tid].cost) {
      switch_membership_l[tid] = true;
      lower[K] += x_cost - points->p[tid].cost;
    } else {
      lower[center_table_l[points->p[tid].assign]] += points->p[tid].cost - x_cost;
    }
  }
  t1 = omp_get_wtime();
  *kernel_t_l += (t1 - t0) * 1000.0;

  t0 = omp_get_wtime();
  t1 = omp_get_wtime();
  *gpu_to_cpu_t_l += (t1 - t0) * 1000.0;

  t0 = omp_get_wtime();
  int number_of_centers_to_close = 0;
  float gl_cost_of_opening_x = z;
  float *gl_lower = &work_mem_h[(size_t)stride * (size_t)nThread];

  for (int i = 0; i < num; i++) {
    if (is_center_l[i]) {
      float low = z;
      for (int j = 0; j < num; j++) {
        low += work_mem_h[(size_t)j * (size_t)stride + center_table_l[i]];
      }
      gl_lower[center_table_l[i]] = low;
      if (low > 0) {
        ++number_of_centers_to_close;
        work_mem_h[(size_t)i * (size_t)stride + K] -= low;
      }
    }
    gl_cost_of_opening_x += work_mem_h[(size_t)i * (size_t)stride + K];
  }

  if (gl_cost_of_opening_x < 0) {
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table_l[points->p[i].assign]] > 0;
      if (switch_membership_l[i] || close_center) {
        points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center_l[i] && gl_lower[center_table_l[i]] > 0) {
        is_center_l[i] = false;
      }
    }

    if (x >= 0 && x < num) is_center_l[x] = true;
    *numcenters = *numcenters + 1 - number_of_centers_to_close;
  } else {
    gl_cost_of_opening_x = 0;
  }

  free(work_mem_h);
  work_mem_h = nullptr;
  t1 = omp_get_wtime();
  *serial_t_l += (t1 - t0) * 1000.0;

  t0 = omp_get_wtime();
  t1 = omp_get_wtime();
  *free_t_l += (t1 - t0) * 1000.0;

  iter++;
  return -gl_cost_of_opening_x;
}

float pspeedy(Points *points, float z, long *kcenter) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;
  for (long i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        float c = distance * points->p[k].weight;
        if (c < points->p[k].cost) {
          points->p[k].cost = c;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
  for (long k = 0; k < points->num; k++) totalcost += points->p[k].cost;

#ifdef PROFILE
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return totalcost;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter_l, float e) {
  (void)kmax;
  long i;
  long x;
  float change = cost;

  while (change / cost > 1.0f * e) {
    change = 0.0;
    intshuffle(feasible, numfeasible);

    for (i = 0; i < iter_l; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
                      isCoordChanged, &serial_t, &cpu_to_gpu_t, &gpu_to_cpu_t,
                      &alloc_t, &kernel_t, &free_t);
    }
    cost -= change;
  }
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc((size_t)numfeasible * sizeof(int));

  if (numfeasible == points->num) {
    for (int i = 0; i < numfeasible; i++) (*feasible)[i] = i;
    return numfeasible;
  }

  float* accumweight = (float*)malloc((size_t)points->num * sizeof(float));
  accumweight[0] = points->p[0].weight;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  float totalweight = accumweight[points->num - 1];

  for (int i = 0; i < numfeasible; i++) {
    float w = (lrand48() / (float)INT_MAX) * totalweight;
    int l = 0, r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      int k = (l + r) / 2;
      if (accumweight[k] > w) r = k;
      else l = k;
    }
    (*feasible)[i] = r;
  }

  free(accumweight);
#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal) {
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  long k = 0;
  int *feasible = nullptr;
  int numfeasible = 0;

  hiz = loz = 0.0f;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  (void)numberOfPoints;
  (void)ptDimension;

  for (long kk = 0; kk < points->num; kk++) {
    hiz += dist(points->p[kk], points->p[0], points->dim) * points->p[kk].weight;
  }

  loz = 0.0f;
  z = (hiz + loz) / 2.0f;

  if (points->num <= kmax) {
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0.0f;
    }
    *kfinal = points->num;
    return 0.0f;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k);

  i = 0;
  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k);
    i++;
  }

  while (k < kmin) {
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, (int)kmin);
  for (int ii = 0; ii < points->num; ii++) {
    is_center[points->p[ii].assign] = true;
  }

  while (1) {
    lastcost = cost;
    (void)lastcost;
    cost = pFL(points, feasible, numfeasible, z, &k, (int)kmax, cost,
               (long)(ITER * kmax * log((float)kmax)), 0.1f);

    if (((k <= (long)(1.1 * kmax)) && (k >= (long)(0.9 * kmin))) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
      cost = pFL(points, feasible, numfeasible, z, &k, (int)kmax, cost,
                 (long)(ITER * kmax * log((float)kmax)), 0.001f);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || (loz >= (0.999f * hiz))) break;
  }

  free(feasible);
  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  for (long i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      float relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (long ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0f - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }
  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset) {
  bool *is_a_median = (bool *)calloc((size_t)points->num, sizeof(bool));
  for (long i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = true;
  }

  long k = centers->num;
  for (long i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, (size_t)points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }
  centers->num = k;
  free(is_a_median);
}

void localSearch(Points* points, long kmin, long kmax, long* kfinal) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  pkmedian(points, kmin, kmax, kfinal);
#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points* centers, long* centerIDs, char* outfile) {
  FILE* fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc((size_t)centers->num, sizeof(int));
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%u\n", (unsigned)centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream* stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char* outfile) {
  float* block = (float*)malloc((size_t)chunksize * (size_t)dim * sizeof(float));
  float* centerBlock = (float*)malloc((size_t)centersize * (size_t)dim * sizeof(float));
  long* centerIDs = (long*)malloc((size_t)centersize * (size_t)dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point*)malloc((size_t)chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[(size_t)i * (size_t)dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point*)malloc((size_t)centersize * sizeof(Point));
  centers.num = 0;
  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[(size_t)i * (size_t)dim];
    centers.p[i].weight = 1.0f;
  }

  long IDoffset = 0;
  long kfinal = 0;
  while (1) {
    size_t numRead = stream->read(block, dim, (int)chunksize);
    fprintf(stderr, "read %d points\n", (int)numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = (long)numRead;
    for (int i = 0; i < points.num; i++) points.p[i].weight = 1.0f;

    switch_membership = (bool*)malloc((size_t)points.num * sizeof(bool));
    is_center = (bool*)calloc((size_t)points.num, sizeof(bool));
    center_table = (int*)malloc((size_t)points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);
    fprintf(stderr, "finish local search\n");

    contcenters(&points);
    isCoordChanged = true;

    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += (long)numRead;

    free(is_center);
    free(switch_membership);
    free(center_table);

    if (stream->feof()) break;
  }

  switch_membership = (bool*)malloc((size_t)centers.num * sizeof(bool));
  is_center = (bool*)calloc((size_t)centers.num, sizeof(bool));
  center_table = (int*)malloc((size_t)centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 10) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n", argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }

  kmin = atol(argv[1]);
  kmax = atol(argv[2]);
  dim = atoi(argv[3]);
  n = atol(argv[4]);
  chunksize = atol(argv[5]);
  clustersize = atol(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  if (nproc > 0) omp_set_num_threads(nproc);

  srand48(SEED);

  PStream* stream = nullptr;
  if (n > 0) stream = new SimStream(n);
  else stream = new FileStream(infilename);

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif

  serial_t = 0.0;
  cpu_to_gpu_t = 0.0;
  gpu_to_cpu_t = 0.0;
  alloc_t = 0.0;
  free_t = 0.0;
  kernel_t = 0.0;
  isCoordChanged = false;

  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);

  freeDevMem();
  freeHostMem();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

